#include <bits/stdc++.h>
using namespace std;
int n,m,k,a[1003],b[1003],c[1003],dp[102][1003];
vector<int> g[102];
int main(){
    scanf("%d%d",&m,&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d%d",&a[i],&b[i],&c[i]);
        k=max(k,c[i]),g[c[i]].push_back(i);
    }
    for(int i=1;i<=k;i++){
        int len=g[i].size();
        for(int j=0;j<=m;j++){
            dp[i][j]=dp[i-1][j];
            for(int k=0;k<len;k++)
                if(j>=a[g[i][k]])
                    dp[i][j]=max(dp[i][j],dp[i-1][j-a[g[i][k]]]+b[g[i][k]]);
        }
    }
    printf("%d",dp[k][m]);
    return 0;
}
